var HistoryModal = class extends import_obsidian3.Modal {
  constructor(app, opts) {
    super(app);
    this.opts = opts;
  }
  onOpen() {
    this.titleEl.setText(this.opts.title);
    const { contentEl } = this;
    contentEl.empty();
    if (this.opts.snapshots.length === 0) {
      contentEl.createEl("p", {
        cls: "mood-history-empty",
        text: "No versions captured yet \u2014 versions are saved as you edit."
      });
      return;
    }
    for (const snap of this.opts.snapshots) {
      const row = contentEl.createDiv({ cls: "mood-history-row" });
      const info = row.createDiv({ cls: "mood-history-info" });
      info.createEl("div", {
        cls: "mood-history-meta",
        text: `${this.opts.formatTime(snap.ts, this.opts.now)} \xB7 ${snap.author}`
      });
      const firstLine = snap.text.replace(/\s+/g, " ").trim().slice(0, 60);
      info.createEl("div", {
        cls: "mood-history-snippet",
        text: firstLine.length > 0 ? firstLine : "(empty)"
      });
      const actions = row.createDiv({ cls: "mood-history-actions" });
      const previewBtn = actions.createEl("button", { text: "Preview" });
      previewBtn.addEventListener("click", () => {
        new SnapshotPreviewModal(this.app, snap).open();
      });
      if (this.opts.readOnly)
        continue;
      const restoreBtn = actions.createEl("button", { text: "Restore", cls: "mod-warning" });
      restoreBtn.addEventListener("click", () => {
        new ConfirmModal(this.app, {
          title: "Restore this version?",
          body: "This replaces the current note content with the selected version for everyone editing it. It is applied as a normal edit, so it merges and propagates to all peers. Continue?",
          confirmText: "Restore",
          onConfirm: () => {
            this.opts.onRestore(snap);
            this.close();
          }
        }).open();
      });
    }
  }
  onClose() {
    this.contentEl.empty();
  }
};
var CommentInputModal = class extends import_obsidian3.Modal {
  constructor(app, opts) {
    super(app);
    this.opts = opts;
    // Detach handle for the textarea's @mention autocomplete; released on close.
    this.detachMention = null;
  }
  onOpen() {
    this.titleEl.setText("Add comment");
    const { contentEl } = this;
    contentEl.empty();
    const quote = this.opts.quote.trim();
    if (quote.length > 0) {
      contentEl.createDiv({ cls: "mood-comment-quote", text: quote });
    }
    const ta = contentEl.createEl("textarea", { cls: "mood-comment-input" });
    ta.rows = 4;
    ta.placeholder = "Write a comment\u2026  (use @name to mention a teammate)";
    const actions = contentEl.createDiv({ cls: "mood-comment-modal-actions" });
    const cancel = actions.createEl("button", { text: "Cancel" });
    const submitBtn = actions.createEl("button", { text: "Comment", cls: "mod-cta" });
    const submit = () => {
      const text2 = ta.value.trim();
      if (text2.length === 0)
        return;
      this.opts.onSubmit(text2);
      this.close();
    };
    cancel.addEventListener("click", () => this.close());
    submitBtn.addEventListener("click", submit);
    ta.addEventListener("keydown", (e) => {
      if (e.key === "Enter" && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        submit();
      }
    });
    this.detachMention = attachMentionAutocomplete(ta, CONFIG.users);
    setTimeout(() => ta.focus(), 0);
  }
  onClose() {
    this.detachMention?.();
    this.detachMention = null;
    this.contentEl.empty();
  }
};
var SetupProgressModal = class extends import_obsidian3.Modal {
  constructor(app, onClosed) {
    super(app);
    this.onClosed = onClosed;
  }
  onOpen() {
    this.titleEl.setText("Mood Collab");
    this.contentEl.addClass("mood-setup");
  }
  render(v) {
    const { contentEl } = this;
    contentEl.empty();
    if (v.phase === "connecting") {
      contentEl.createEl("p", { cls: "mood-setup-head", text: "Connecting to the workspace\u2026" });
      contentEl.createEl("p", { cls: "mood-setup-sub", text: "Reaching the team server." });
      return;
    }
    if (v.phase === "ready") {
      contentEl.createEl("p", { cls: "mood-setup-head", text: "Workspace ready" });
      const noun = v.readyCount === 1 ? "note" : "notes";
      contentEl.createEl("p", {
        cls: "mood-setup-sub",
        text: `${v.readyCount} ${noun} synced. You're connected.`
      });
      const actions = contentEl.createDiv({ cls: "mood-setup-actions" });
      actions.createEl("button", { cls: "mood-setup-btn", text: "Done" }).addEventListener("click", () => this.close());
      return;
    }
    const seeding = v.role === "seeding";
    contentEl.createEl("p", {
      cls: "mood-setup-head",
      text: seeding ? "You're the first one here" : "Joining the team workspace"
    });
    contentEl.createEl("p", {
      cls: "mood-setup-sub",
      text: v.phase === "uploading" ? seeding ? "Uploading your GDD to the team workspace\u2026" : "Syncing your notes\u2026" : "Receiving the team's GDD\u2026"
    });
    const bar = contentEl.createDiv({ cls: "mood-setup-bar" });
    const fill = bar.createDiv({ cls: "mood-setup-bar-fill" });
    fill.style.width = `${v.total > 0 ? Math.round(v.done / v.total * 100) : 0}%`;
    contentEl.createEl("p", { cls: "mood-setup-count", text: `${v.done} / ${v.total} notes` });
    contentEl.createEl("p", { cls: "mood-setup-note", text: "Keep Obsidian open until this finishes." });
  }
  onClose() {
    this.contentEl.empty();
    this.onClosed();
  }
};
