    for (const [vpath, live] of this.open) {
      await this.untrackLiveDoc(vpath, live);
      live.destroy();
    }
    this.open.clear();
    for (const t of this.snapshotTimers.values())
      window.clearTimeout(t);
    this.snapshotTimers.clear();
    for (const off of this.textUnobservers.values())
      off();
    this.textUnobservers.clear();
    this.lastSnapText.clear();
