  pushActivityEntry(e) {
    const adoc = this.docForVpath(e.vpath);
    if (!adoc || !this.user)
      return;
    pushActivity(
      adoc,
      {
        id: crypto.randomUUID(),
        ts: Date.now(),
        actorId: this.user.userId,
        actorName: this.user.name,
        type: e.type,
        vpath: e.vpath,
        summary: e.summary
      },
      ACTIVITY_MAX
    );
  }
  // ---------------------------------------------------------------------------
  // Wave D2: @mention notifications (routed through the index activity feed)
